select count(*) from postgres.posthistory as ph, postgres.posts as p, postgres.votes as v, postgres.users as u where u.id = p.owneruserid and p.id = ph.postid and p.id = v.postid and ph.creationdate<=timestamp '2014-07-28 13:25:35' and p.posttypeid=1 and p.answercount>=0 and p.answercount<=4 and v.creationdate>=timestamp '2010-07-20 00:00:00' and v.creationdate<=timestamp '2014-09-03 00:00:00' and u.downvotes=0 and u.creationdate<=timestamp '2014-08-08 07:03:29';
